<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    <StepIndicator CurrentStep="_currentStep"
                   CompletedSteps="_completedSteps"
                   OnStepClicked="GoToStep" />

    <div class="mt-4">
        @switch (_currentStep)
        {
            case 1:
                <PersonalInfoStep Model="_personalInfo"
                                  EmailError="@_emailError"
                                  IsValidating="_isValidatingEmail"
                                  OnNext="HandlePersonalInfoNext" />
                break;

            case 2:
                <WorkHistoryStep Entries="_workEntries"
                                 OnBack="() => GoToStep(1)"
                                 OnNext="() => CompleteAndAdvance(2)" />
                break;

            case 3:
                <ReferencesStep References="_references"
                                OnBack="() => GoToStep(2)"
                                OnNext="() => CompleteAndAdvance(3)" />
                break;

            case 4:
                <CoverLetterStep CoverLetter="@_coverLetter"
                                 CoverLetterChanged="v => _coverLetter = v"
                                 OnBack="() => GoToStep(3)"
                                 OnNext="() => CompleteAndAdvance(4)" />
                break;

            case 5:
                <ReviewStep Personal="_personalInfo"
                            WorkEntries="_workEntries"
                            References="_references"
                            CoverLetter="@_coverLetter"
                            IsSubmitting="_isSubmitting"
                            Submitted="_submitted"
                            ApplicationId="_applicationId"
                            SubmitError="@_submitError"
                            OnBack="() => GoToStep(4)"
                            OnEditSection="GoToStep"
                            OnSubmit="HandleSubmit" />
                break;
        }
    </div>
</div>

@code {
    private int _currentStep = 1;
    private readonly HashSet<int> _completedSteps = new();

    // Form state
    private readonly PersonalInfoModel _personalInfo = new();
    private readonly List<WorkEntryModel> _workEntries = [new WorkEntryModel()];
    private readonly List<ReferenceModel> _references = [new ReferenceModel(), new ReferenceModel()];
    private string _coverLetter = "";

    // UI state
    private string? _emailError;
    private bool _isValidatingEmail;
    private bool _isSubmitting;
    private bool _submitted;
    private int _applicationId;
    private string? _submitError;

    private void GoToStep(int step)
    {
        _currentStep = step;
    }

    private void CompleteAndAdvance(int completedStep)
    {
        _completedSteps.Add(completedStep);
        _currentStep = completedStep + 1;
    }

    private async Task HandlePersonalInfoNext()
    {
        _emailError = null;
        _isValidatingEmail = true;

        try
        {
            var isValid = await ApplicationService.ValidateEmailAsync(_personalInfo.Email);
            if (!isValid)
            {
                _emailError = "Please enter a valid email address.";
                return;
            }

            CompleteAndAdvance(1);
        }
        finally
        {
            _isValidatingEmail = false;
        }
    }

    private async Task HandleSubmit()
    {
        _submitError = null;
        _isSubmitting = true;

        try
        {
            var application = new JobApplication(
                _personalInfo.ToRecord(),
                new WorkHistory(_workEntries.Select(e => e.ToRecord()).ToList()),
                _references.Select(r => r.ToRecord()).ToList(),
                _coverLetter
            );

            _applicationId = await ApplicationService.SubmitApplicationAsync(application);
            _submitted = true;
        }
        catch (Exception ex)
        {
            _submitError = $"Submission failed: {ex.Message}. Please try again.";
        }
        finally
        {
            _isSubmitting = false;
        }
    }
}

